{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 smoke 테스트 통과를 전제로 금요일 15:00 KST로 한다.",
        "condition": "smoke 테스트 통과",
        "certainty": "confirmed"
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인한다.",
        "condition": "packageName mismatch 발생 시",
        "certainty": "confirmed"
      },
      {
        "decision": "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다.",
        "condition": "package contract가 잘못된 것으로 확인된 경우",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "proposed_by": "Hara",
        "outcome": "rejected",
        "certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposed_by": "Seoyeon",
        "status": "internal stretch goal only",
        "reason": "Doyun이 smoke 테스트 선통과 필요성을 제기했으며, 최종 공개 릴리스 목표는 금요일 15:00 KST로 결정됨"
      }
    ],
    "non_decisions": [
      {
        "item": "README install steps를 목요일까지 검토하면 좋다는 의견",
        "status": "owner not assigned",
        "certainty": "mentioned but not confirmed as assigned action"
      },
      {
        "item": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부",
        "status": "not decided",
        "certainty": "open question"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path가 릴리스를 지연시킬 수 있음",
        "certainty": "confirmed"
      },
      {
        "risk": "README install steps가 오래된 경우 릴리스 노트가 사용자를 오도할 수 있음",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "certainty": "confirmed open question"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?",
        "certainty": "confirmed open question"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicitly stated"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicitly stated"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 generated tarball path를 확인한다.",
      "due": null,
      "status": "confirmed, deadline not specified",
      "source_certainty": "explicitly stated"
    },
    {
      "owner": null,
      "task": "README install steps를 목요일까지 가능하면 검토한다.",
      "due": "목요일 if possible",
      "status": "mentioned, not assigned",
      "source_certainty": "owner not assigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST smoke 테스트 결과 공유 여부",
      "Doyun의 금요일 12:00 KST action_items.md failure triage note 작성 여부",
      "smoke 결과 게시 후 Hara의 generated tarball path 확인 결과",
      "README install steps 검토 담당자 지정 여부",
      "최종 릴리스 승인 권한자 확인",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정"
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "명시되지 않은 owner",
      "명시되지 않은 deadline"
    ]
  },
  "non_invention_rules": {
    "customer": "회의 노트에 고객 또는 외부 파트너가 명시되지 않았으므로 생성하지 않는다.",
    "budget": "예산 관련 사실은 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "owners": "명시된 owner만 기록하고, README 검토 owner는 null로 둔다.",
    "deadlines": "명시된 due만 기록하고, Hara의 정확한 deadline은 null로 둔다."
  }
}
